import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { EventBus } from '../../src/events/event-bus.js';
import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
import {
  NotificationHistoryService,
  resetLogIdCounter,
} from '../../src/services/notification-history.service.js';
import {
  NotificationService,
  resetNotificationIdCounter,
} from '../../src/services/notification.service.js';
import { EmailAdapter } from '../../src/adapters/email.adapter.js';
import type { NotificationResult } from '../../src/models/notification.js';
import type { OrderCreatedEvent, UserCreatedEvent } from '../../src/events/event-types.js';

function makeResult(overrides: Partial<NotificationResult> = {}): NotificationResult {
  return {
    success: true,
    notification: {
      id: 'notif-0001',
      type: 'order-confirmation',
      channel: 'email',
      recipient: 'alice@example.com',
      subject: 'Order Confirmation',
      body: 'Your order has been placed.',
      priority: 'normal',
      createdAt: new Date('2026-03-01T10:00:00Z'),
      metadata: { orderId: 'order-1', userId: 'user-1' },
    },
    deliveredAt: new Date('2026-03-01T10:00:01Z'),
    ...overrides,
  };
}

describe('NotificationHistoryService', () => {
  let db: Database;
  let repository: NotificationLogRepository;
  let historyService: NotificationHistoryService;

  beforeEach(() => {
    db = new Database();
    repository = new NotificationLogRepository(db);
    historyService = new NotificationHistoryService(repository);
    resetLogIdCounter();
  });

  describe('logNotification', () => {
    it('should log a successful notification as delivered', () => {
      const result = makeResult();
      const entry = historyService.logNotification(result);

      expect(entry.id).toBe('nlog-0001');
      expect(entry.notificationId).toBe('notif-0001');
      expect(entry.recipient).toBe('alice@example.com');
      expect(entry.channel).toBe('email');
      expect(entry.type).toBe('order-confirmation');
      expect(entry.subject).toBe('Order Confirmation');
      expect(entry.status).toBe('delivered');
      expect(entry.error).toBeUndefined();
      expect(entry.priority).toBe('normal');
      expect(entry.metadata).toEqual({ orderId: 'order-1', userId: 'user-1' });
    });

    it('should log a failed notification', () => {
      const result = makeResult({
        success: false,
        error: 'Connection timeout',
      });
      const entry = historyService.logNotification(result);

      expect(entry.status).toBe('failed');
      expect(entry.error).toBe('Connection timeout');
    });

    it('should log a suppressed notification', () => {
      const result = makeResult();
      const entry = historyService.logNotification(result, { suppressed: true });

      expect(entry.status).toBe('suppressed');
    });

    it('should generate sequential log IDs', () => {
      const r1 = historyService.logNotification(makeResult());
      const r2 = historyService.logNotification(makeResult({
        notification: { ...makeResult().notification, id: 'notif-0002' },
      }));

      expect(r1.id).toBe('nlog-0001');
      expect(r2.id).toBe('nlog-0002');
    });

    it('should persist the entry in the repository', () => {
      historyService.logNotification(makeResult());
      expect(repository.count()).toBe(1);
    });
  });

  describe('query', () => {
    beforeEach(() => {
      // Log several notifications for query tests
      historyService.logNotification(makeResult());
      historyService.logNotification(makeResult({
        notification: {
          ...makeResult().notification,
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'welcome',
          channel: 'email',
          createdAt: new Date('2026-03-02T10:00:00Z'),
        },
      }));
      historyService.logNotification(makeResult({
        success: false,
        error: 'Failed',
        notification: {
          ...makeResult().notification,
          id: 'notif-0003',
          recipient: 'alice@example.com',
          type: 'order-status-update',
          channel: 'webhook',
          createdAt: new Date('2026-03-03T10:00:00Z'),
        },
      }));
    });

    it('should filter by recipient', () => {
      const results = historyService.query({ recipient: 'alice@example.com' });
      expect(results).toHaveLength(2);
      results.forEach((r) => expect(r.recipient).toBe('alice@example.com'));
    });

    it('should filter by type', () => {
      const results = historyService.query({ type: 'welcome' });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('welcome');
    });

    it('should filter by channel', () => {
      const results = historyService.query({ channel: 'webhook' });
      expect(results).toHaveLength(1);
      expect(results[0]?.channel).toBe('webhook');
    });

    it('should filter by status', () => {
      const results = historyService.query({ status: 'failed' });
      expect(results).toHaveLength(1);
      expect(results[0]?.error).toBe('Failed');
    });

    it('should filter by date range', () => {
      const results = historyService.query({
        startDate: new Date('2026-03-02T00:00:00Z'),
        endDate: new Date('2026-03-02T23:59:59Z'),
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.recipient).toBe('bob@example.com');
    });

    it('should combine multiple filters with AND logic', () => {
      const results = historyService.query({
        recipient: 'alice@example.com',
        status: 'failed',
      });
      expect(results).toHaveLength(1);
      expect(results[0]?.type).toBe('order-status-update');
    });

    it('should return all entries when no filters are provided', () => {
      const results = historyService.query({});
      expect(results).toHaveLength(3);
    });

    it('should return empty array when no entries match', () => {
      const results = historyService.query({ recipient: 'nobody@example.com' });
      expect(results).toHaveLength(0);
    });
  });

  describe('convenience methods', () => {
    beforeEach(() => {
      historyService.logNotification(makeResult());
      historyService.logNotification(makeResult({
        notification: {
          ...makeResult().notification,
          id: 'notif-0002',
          recipient: 'bob@example.com',
          type: 'welcome',
        },
      }));
    });

    it('getByRecipient should return entries for a recipient', () => {
      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.recipient).toBe('alice@example.com');
    });

    it('getByType should return entries for a notification type', () => {
      const entries = historyService.getByType('welcome');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.type).toBe('welcome');
    });

    it('getByDateRange should return entries in range', () => {
      const entries = historyService.getByDateRange(
        new Date('2026-03-01T00:00:00Z'),
        new Date('2026-03-01T23:59:59Z'),
      );
      expect(entries).toHaveLength(2);
    });

    it('getById should return a specific entry', () => {
      const entry = historyService.getById('nlog-0001');
      expect(entry).toBeDefined();
      expect(entry?.notificationId).toBe('notif-0001');
    });

    it('getById should return undefined for non-existent entry', () => {
      expect(historyService.getById('nlog-9999')).toBeUndefined();
    });

    it('getCount should return total number of log entries', () => {
      expect(historyService.getCount()).toBe(2);
    });
  });

  describe('integration with NotificationService', () => {
    let eventBus: EventBus;
    let notificationService: NotificationService;
    let emailAdapter: EmailAdapter;

    beforeEach(() => {
      eventBus = new EventBus();
      notificationService = new NotificationService(eventBus);
      emailAdapter = new EmailAdapter();
      notificationService.registerAdapter(emailAdapter);
      notificationService.setHistoryService(historyService);
      resetNotificationIdCounter();
    });

    it('should log notifications sent via EventBus events', async () => {
      const event: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
          total: 20,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      expect(historyService.getCount()).toBe(1);
      const entries = historyService.getByRecipient('alice@example.com');
      expect(entries).toHaveLength(1);
      expect(entries[0]?.status).toBe('delivered');
      expect(entries[0]?.type).toBe('order-confirmation');
      expect(entries[0]?.channel).toBe('email');
    });

    it('should log failed notifications when no adapter is registered', async () => {
      const noAdapterService = new NotificationService(new EventBus());
      noAdapterService.setHistoryService(historyService);

      await noAdapterService.send({
        type: 'welcome',
        channel: 'email',
        recipient: 'test@example.com',
        subject: 'Test',
        body: 'Test body',
      });

      const entries = historyService.query({ status: 'failed' });
      expect(entries).toHaveLength(1);
      expect(entries[0]?.error).toContain('No adapter registered');
    });

    it('should log multiple notifications from different events', async () => {
      const orderEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const userEvent: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-2',
          name: 'Bob',
          email: 'bob@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(orderEvent);
      await eventBus.emit(userEvent);

      expect(historyService.getCount()).toBe(2);
      expect(historyService.getByRecipient('alice@example.com')).toHaveLength(1);
      expect(historyService.getByRecipient('bob@example.com')).toHaveLength(1);
    });

    it('should work without history service (backwards-compatible)', async () => {
      const plainService = new NotificationService(eventBus);
      plainService.registerAdapter(emailAdapter);
      // No setHistoryService call

      const event: UserCreatedEvent = {
        type: 'user:created',
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      await eventBus.emit(event);

      // Should not throw; notification still sent
      expect(plainService.getNotificationCount()).toBe(1);
    });
  });
});

