+/**
+ * Notification history service — logs every sent notification and provides
+ * query capabilities over the history.
+ *
+ * Designed to be injected into NotificationService via setHistoryService().
+ * The NotificationService calls logNotification() after every send attempt,
+ * and this service persists the log entry via NotificationLogRepository.
+ */
+
+import type { NotificationResult } from '../models/notification.js';
+import type {
+  NotificationLogEntry,
+  NotificationHistoryQuery,
+  DeliveryStatus,
+} from '../models/notification-log.js';
+import type { NotificationLogRepository } from '../repositories/notification-log.repository.js';
+import { Logger } from '../utils/logger.js';
+
+let nextLogId = 1;
+
+function generateLogId(): string {
+  return `nlog-${String(nextLogId++).padStart(4, '0')}`;
+}
+
+export function resetLogIdCounter(): void {
+  nextLogId = 1;
+}
+
+export class NotificationHistoryService {
+  private logger = new Logger('NotificationHistoryService');
+
+  constructor(private repository: NotificationLogRepository) {}
+
+  /**
+   * Log a notification result. Called by NotificationService after every
+   * send attempt (success, failure, or suppression).
+   */
+  logNotification(
+    result: NotificationResult,
+    options?: { suppressed?: boolean },
+  ): NotificationLogEntry {
+    let status: DeliveryStatus;
+    if (options?.suppressed) {
+      status = 'suppressed';
+    } else if (result.success) {
+      status = 'delivered';
+    } else {
+      status = 'failed';
+    }
+
+    const entry: NotificationLogEntry = {
+      id: generateLogId(),
+      notificationId: result.notification.id,
+      recipient: result.notification.recipient,
+      channel: result.notification.channel,
+      type: result.notification.type,
+      subject: result.notification.subject,
+      status,
+      error: result.error,
+      priority: result.notification.priority,
+      metadata: result.notification.metadata,
+      createdAt: result.notification.createdAt,
+      deliveredAt: result.deliveredAt,
+    };
+
+    this.repository.save(entry);
+    this.logger.info(
+      `Logged notification ${entry.notificationId} [${status}] to ${entry.recipient} via ${entry.channel}`,
+    );
+
+    return entry;
+  }
+
+  /**
+   * Query notification history with optional filters.
+   * All filter criteria are combined with AND logic.
+   */
+  query(filter: NotificationHistoryQuery): NotificationLogEntry[] {
+    return this.repository.findAll((entry) => {
+      if (filter.recipient && entry.recipient !== filter.recipient) return false;
+      if (filter.type && entry.type !== filter.type) return false;
+      if (filter.channel && entry.channel !== filter.channel) return false;
+      if (filter.status && entry.status !== filter.status) return false;
+      if (filter.startDate && entry.createdAt < filter.startDate) return false;
+      if (filter.endDate && entry.createdAt > filter.endDate) return false;
+      return true;
+    });
+  }
+
+  /**
+   * Get all log entries for a specific recipient.
+   */
+  getByRecipient(recipient: string): NotificationLogEntry[] {
+    return this.repository.findByRecipient(recipient);
+  }
+
+  /**
+   * Get all log entries for a specific notification type.
+   */
+  getByType(type: NotificationLogEntry['type']): NotificationLogEntry[] {
+    return this.repository.findByType(type);
+  }
+
+  /**
+   * Get all log entries within a date range.
+   */
+  getByDateRange(startDate: Date, endDate: Date): NotificationLogEntry[] {
+    return this.repository.findByDateRange(startDate, endDate);
+  }
+
+  /**
+   * Get a single log entry by ID.
+   */
+  getById(id: string): NotificationLogEntry | undefined {
+    return this.repository.findById(id);
+  }
+
+  /**
+   * Get total count of logged notifications.
+   */
+  getCount(): number {
+    return this.repository.count();
+  }
+}

